targets.expr:
sum(
  max(kube_pod_labels{cluster_name="$cluster_name",namespace=~"$namespace",pod=~"$pod"}) by (namespace, pod)
  *
  on(pod)
  group_right(namespace)
  sum (
    kube_pod_container_resource_requests{cluster_name="$cluster_name",resource="cpu"}
  ) by (pod)
)

sum(
  max(kube_pod_labels{cluster_name="$cluster_name",namespace=~"$namespace",pod=~"$pod"}) by (namespace, pod)
  *
  on(pod)
  group_right(namespace)
  sum (
    kube_pod_container_resource_requests{cluster_name="$cluster_name",resource="memory"}
  ) by (pod)
)
